"""
MKT Original Language Commentary — Psalms chapters 107–110 (92 missing verses)
Run: python3 scripts/zc-original-psalms-107-110.py

Key decisions in this range:
- Ps 107: the great fourfold thanksgiving psalm (43 vv); four rescue strophes sharing
  the same refrain (vv8/15/21/31: yôdû layhwāh ḥasdô wĕniplĕʾōtāyw libnê ʾādām);
  ṣalmāwet (shadow of death, v10) = Isa 9:1/Matt 4:16; shālaḥ dĕbārô (he sent his
  word, v20) as hypostatic Word healing the sick (→ John 1); seamanship swallowed
  (ḥokhmātām titbāllāʿ, v27); wisdom epilogue: mî-ḥākhām (v43)
- Ps 108: composite (Ps 57:7-11 + Ps 60:5-12); divine oracle dividing the land (vv7-9)
  with the derisive images for Moab/Edom/Philistia; shāwĕʾ tĕshûʿat ʾādām (human
  help is vanity, v12)
- Ps 109: the supreme imprecatory psalm; key interpretive question whether vv6-20 are
  Psalmist's curses OR quotation of what enemies say against him; sāṭān (accuser/
  adversary, v6) as legal-court figure; v8 cited in Acts 1:20 for Judas; waʾănî tĕpillāh
  (but I am prayer, v4) — unique self-identification; head-shaking (v25) parallels
  Ps 22:7 and crucifixion scene (Matt 27:39); v31 inversion: he stands at the
  right hand of the poor (contrast v6: enemy sets accuser at the right hand)
- Ps 110: only vv2,3,5,6,7 needed (v1 and v4 already written); maṭṭēh-ʿuzzĕkā
  (rod of your strength, v2); nĕdābōt (volunteers/freewill offerings, v3); the
  ʾădōnāy ʿal-yĕmînĕkā (Lord at your right hand, v5) — inversion of v1's structure;
  minnaḥal badderek yishteh (drinking from the stream mid-battle, v7)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 107-110 — the great fourfold thanksgiving (107),
#   the composite land-oracle psalm (108), the supreme imprecatory psalm with the
#   Acts 1:20 Judas application (109), and the completion of Ps 110's messianic
#   priest-king portrait (vv2,3,5,6,7 only — v1 and v4 already present).
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(107,111)])"

PSALMS = {
  "107": {
    "1": '<p><strong>הוֹדוּ לַיהוָה כִּי-טוֹב כִּי לְעוֹלָם חַסְדּוֹ</strong> (<em>hôdû layhwāh kî-ṭôb kî lĕʿôlām ḥasdô</em>, "Give thanks to the LORD, for he is good; his steadfast love endures forever!") — the hallel formula (Ps 100:5; 106:1; 118:1,29; 136 — where it forms the refrain after every verse). <em>Hôdû</em>: acknowledge, give thanks (from <em>yādāh</em>: to extend the hand in acknowledgment — both to confess and to praise). <em>Kî-ṭôb</em>: because he is good (not merely because of his benefits). <em>Kî lĕʿôlām ḥasdô</em>: because his steadfast love endures forever — the unbounded duration of the covenant commitment that makes giving thanks not merely appropriate but safe: the God thanked will not withdraw. Psalm 107 is the only psalm to open with the <em>hallel</em> formula and then follow it with four extended narrative strophes.</p>',
    "2": '<p><strong>יֹאמְרוּ גְּאוּלֵי יְהוָה אֲשֶׁר גְּאָלָם מִיַּד-צָר</strong> (<em>yōʾmĕrû gĕʾûlê yĕhwāh ʾăsher gĕʾālām miyyad-ṣār</em>, "Let those the LORD has redeemed declare it — those he bought back from the grip of the enemy!") — <em>gĕʾûlê yĕhwāh</em>: the redeemed of the LORD (from <em>gāʾal</em>: the kinsman-redeemer word — the family obligation to buy back a relative from slavery or debt — Lev 25:25,47-55; Ruth 3-4; Isa 41:14; 43:1,14). This is not a commercial purchase but a covenantal rescue by the divine next-of-kin. <em>Miyyad-ṣār</em>: from the hand of the adversary/oppressor (the grip of the enemy treated as a physical clench from which the redeemed must be pried). The psalm summons this specific community — the redeemed — as its primary narrators.</p>',
    "3": '<p><strong>וּמֵאֲרָצוֹת קִבְּצָם מִמִּזְרָח וּמִמַּעֲרָב מִצָּפוֹן וּמִיָּם</strong> (<em>ûmêʾărāṣôt qibbĕṣām mimmizrāḥ ûmimmaʿărāb miṣṣāpôn ûmiyyām</em>, "gathered in from every land — from east and west, from north and south!") — the four compass directions (east, west, north, and <em>yām</em> = the sea/south in Israel\'s orientation where the west = the Mediterranean and "south" was often specified as sea). The exile-return motif: God gathered scattered Israel from the whole world (Isa 43:5-6: "I will bring your offspring from the east and gather you from the west; I will say to the north, \'Give them up\'"; Deut 30:3-5). The geographical comprehensiveness grounds the prayer for any exile from any direction.</p>',
    "4": '<p><strong>תָּעוּ בַמִּדְבָּר בִּישִׁימוֹן דָּרֶךְ עִיר מוֹשָׁב לֹא מָצָאוּ</strong> (<em>tāʿû bammidbar bîshîmôn dārek ʿîr môshāb lōʾ māṣāʾû</em>, "Some wandered in the desert waste, finding no road to a city where they could live!") — <em>tāʿû</em>: they wandered (the word for going astray — sheep without a shepherd: Isa 53:6: "we all like sheep have gone astray"). <em>Bammidbar bîshîmôn</em>: in the wilderness, in the desert/waste (the doubled synonyms emphasizing the uninhabited, trackless character of the place). <em>Tōhû</em> in Hebrew: desert-waste (the word of Gen 1:2 for the pre-creation formlessness — the wanderers are in a pre-civilizational void where there is no city, no road, no <em>môshāb</em>/habitation). The Exodus wilderness is the paradigm.</p>',
    "5": '<p><strong>רְעֵבִים גַּם-צְמֵאִים נַפְשָׁם בָּהֶם תִּתְעַטָּף</strong> (<em>rĕʿêbîm gam-ṣĕmêʾîm napshām bāhem titʿaṭṭāp</em>, "Hungry and thirsty, their soul grew faint within them!") — <em>rĕʿêbîm gam-ṣĕmêʾîm</em>: hungry and also thirsty — the two fundamental physical needs in the wilderness. <em>Napshām bāhem titʿaṭṭāp</em>: "their soul fainted within them" (<em>ʿāṭap</em>: to be weak, to faint — Ps 61:2; 77:3; Lam 2:11,19: souls fainting in the city streets). The <em>nefesh</em> (soul/life-breath) is reduced to fainting — the vital force nearly extinguished. This physical extremity is the trigger for the cry of v6.</p>',
    "6": '<p><strong>וַיִּצְעֲקוּ אֶל-יְהוָה בַּצַּר לָהֶם מִמְּצוּקוֹתֵיהֶם יַצִּילֵם</strong> (<em>wayyiṣʿăqû ʾel-yĕhwāh baṣṣar lāhem mimmĕṣûqôtêhem yaṣṣîlêm</em>, "Then they cried to the LORD in their trouble, and he rescued them from their distresses!") — the first occurrence of the cry-response pattern that repeats in all four strophes (vv6/13/19/28). <em>Ṣāʿaq</em>: to cry out (the urgent, loud cry of distress — Exod 2:23: "the Israelites groaned and cried out"; 8:12: Moses cried out). <em>Baṣṣar lāhem</em>: in their tight/narrow place (the distress of being squeezed — Ps 18:6; 102:2). <em>Mimmĕṣûqôtêhem yaṣṣîlêm</em>: from their distresses he rescued them — immediate, specific, effective rescue.</p>',
    "7": '<p><strong>וַיַּדְרִיכֵם בְּדֶרֶךְ יְשָׁרָה לָלֶכֶת אֶל-עִיר מוֹשָׁב</strong> (<em>wayyadrîkhêm bĕderek yĕshārāh lāleket ʾel-ʿîr môshāb</em>, "He guided them on a straight path to a city where they could settle!") — <em>hidrîk</em> (hiphil of <em>dārak</em>: to tread a path — to walk, but here causatively: to cause to walk, to guide). The one who guides the blind on a road they did not know (Isa 42:16). <em>Bĕderek yĕshārāh</em>: on a straight/level path (the opposite of the trackless waste of v4). <em>ʿÎr môshāb</em>: a city of habitation — the specific answer to the specific need of v4 (finding "no road to a city"). The divine guidance creates the very road and destination that was utterly absent.</p>',
    "8": '<p><strong>יוֹדוּ לַיהוָה חַסְדּוֹ וְנִפְלְאוֹתָיו לִבְנֵי אָדָם</strong> (<em>yôdû layhwāh ḥasdô wĕnipĕlĕʾōtāyw libnê ʾādām</em>, "Let them give thanks to the LORD for his steadfast love and for his wonders done for the children of man!") — the first refrain (repeated verbatim at vv15, 21, 31 — the structural spine of the psalm). <em>Yôdû</em>: let them give thanks (the same root as <em>hôdû</em> in v1). <em>Ḥasdô</em>: his steadfast love (the covenant-faithfulness). <em>Nipĕlĕʾōtāyw libnê ʾādām</em>: his wonders for the sons of Adam/humanity (the acts that exceed human comprehension — Exod 15:11; Ps 77:11). The refrain connects each rescue to the same two divine attributes: the character (<em>ḥesed</em>) and the actions (<em>nipĕlāʾôt</em>).</p>',
    "9": '<p><strong>כִּי-הִשְׂבִּיעַ נֶפֶשׁ שֹׁקֵקָה וְנֶפֶשׁ רְעֵבָה מִלֵּא-טוֹב</strong> (<em>kî-hisbîaʿ nefesh shōqēqāh wĕnefesh rĕʿêbāh millêʾ-ṭôb</em>, "For he gives what the hungry soul longs for and fills the starving soul with good things!") — the explanatory <em>kî</em>-clause expanding the refrain with the specific act. <em>Nefesh shōqēqāh</em>: the longing/thirsting soul (<em>shāqaq</em>: to rush, to long — the intense craving of the dehydrated). <em>Hisbîaʿ</em> (hiphil: to satisfy to the full — the same verb as Ps 17:15: "I shall be satisfied when I awake"; Ps 22:26: the afflicted shall eat and be satisfied). <em>Millêʾ-ṭôb</em>: filled with good things — Luke 1:53 echoes this: "he has filled the hungry with good things and the rich he has sent away empty."</p>',
    "10": '<p><strong>יֹשְׁבֵי חֹשֶׁךְ וְצַלְמָוֶת אֲסִירֵי עֳנִי וּבַרְזֶל</strong> (<em>yōshĕbê ḥōshek wĕṣalmāwet ʾăsîrê ʿŏnî ûbarzel</em>, "Some sat in darkness and the shadow of death, bound in misery and iron chains!") — the second strophe (vv10-16): the prisoners. <em>Ṣalmāwet</em>: shadow of death (the Hebrew compound of <em>ṣēl</em>/shadow and <em>māwet</em>/death — the darkest darkness imaginable, the gloom of the underworld entrance — Job 3:5; 10:21-22; 24:17; Ps 23:4). This word appears in Isa 9:1 ("people who walked in darkness have seen a great light; on those living in the land of the shadow of death, light has dawned") — quoted in Matt 4:16 as Jesus\'s coming to Galilee. <em>ʾĂsîrê ʿŏnî ûbarzel</em>: bound in affliction and iron — the double constraint of suffering and physical chains.</p>',
    "11": '<p><strong>כִּי-מָרוּ אִמְרֵי אֵל וַעֲצַת עֶלְיוֹן נָאָצוּ</strong> (<em>kî-mārû ʾimrê ʾêl waʿăṣat ʿelyôn nāʾāṣû</em>, "for they had defied the commands of God and rejected the plan of the Most High!") — the explanation of the imprisonment: willful rebellion against the divine word. <em>Mārāh</em>: to be contentious, to rebel (Num 20:24; Deut 1:26,43: Israel\'s rebellion in the wilderness). <em>ʾImrê ʾêl</em>: the words/commands of God. <em>ʿĂṣat ʿelyôn nāʾāṣû</em>: they spurned/despised the counsel of the Most High (<em>nāʾaṣ</em>: to treat with contempt — Num 14:11: "how long will they treat me with contempt?"). The connection between sin and bondage is explicit: the darkness is the consequence of defiance. But the refrain\'s rescue (v14) happens despite the cause.</p>',
    "12": '<p><strong>וַיַּכְנַע בֶּעָמָל לִבָּם כָּשְׁלוּ וְאֵין עֹזֵר</strong> (<em>wayyakhnаʿ beʿāmāl libbām kāshĕlû wĕʾên ʿōzêr</em>, "So he wore them down with grinding toil; they stumbled and fell, with no one to help!") — <em>kānaʿ</em> (hiphil: to humble, to subjugate — the divine bringing-low as discipline): God employed their own consequence to break their resistance. <em>Beʿāmāl</em>: in/through toil/misery (the labor that is also suffering — Eccl 1:3; 2:10). <em>Kāshĕlû wĕʾên ʿōzêr</em>: they stumbled and there was no helper — the consequence of the defiance of v11 is isolation: the one who rejected divine counsel finds no human counsel available either.</p>',
    "13": '<p><strong>וַיִּזְעֲקוּ אֶל-יְהוָה בַּצַּר לָהֶם מִמְּצוּקוֹתֵיהֶם יוֹשִׁיעֵם</strong> (<em>wayyizʿăqû ʾel-yĕhwāh baṣṣar lāhem mimmĕṣûqôtêhem yôshîʿêm</em>, "Then they cried to the LORD in their trouble, and he saved them from their distresses!") — the second occurrence of the cry-and-rescue pattern. Note the variation: v6 uses <em>yaṣṣîlêm</em> (he rescued/snatched away) while v13 uses <em>yôshîʿêm</em> (he saved — <em>yāshaʿ</em>: the verb behind <em>yĕshûʿāh</em>/salvation and the name Jesus). The two verbs are synonymous in rescue-language but <em>yāshaʿ</em> carries the additional freight of the Exodus salvation (Exod 14:30: "the LORD saved Israel that day") and the messianic name.</p>',
    "14": '<p><strong>יוֹצִיאֵם מֵחֹשֶׁךְ וְצַלְמָוֶת וּמוֹסְרוֹתֵיהֶם יְנַתֵּק</strong> (<em>yôṣîʾêm mêḥōshek wĕṣalmāwet ûmôsĕrôtêhem yĕnattêq</em>, "He led them out of the darkness and the shadow of death and broke their bonds apart!") — <em>yôṣîʾ</em> (hiphil: to bring out — the Exodus verb: Exod 13:3,9,14,16: "the LORD brought you out"). From <em>ḥōshek wĕṣalmāwet</em> (the darkest dark of v10) into freedom. <em>Yĕnattêq</em>: he snapped/broke apart (<em>nātaq</em>: to tear loose, to sever — Acts 2:24 quotes Ps 16:10 with the same semantic field for the resurrection). The iron chains of v10 are broken by the one who does wonders.</p>',
    "15": '<p>The second refrain, identical to v8: <strong>יוֹדוּ לַיהוָה חַסְדּוֹ וְנִפְלְאוֹתָיו לִבְנֵי אָדָם</strong> (<em>yôdû layhwāh ḥasdô wĕnipĕlĕʾōtāyw libnê ʾādām</em>) — "Let them give thanks to the LORD for his steadfast love and for his wonders done for the children of man!" The refrain\'s exact repetition after each rescue is the psalm\'s liturgical genius: the same God who rescued the wanderers from the desert (v4) rescued the prisoners from the darkness. The identical words applied to different situations assert a single unified character behind all the rescues.</p>',
    "16": '<p><strong>כִּי-שִׁבַּר דַּלְתוֹת נְחֹשֶׁת וּבְרִיחֵי בַרְזֶל גִּדֵּעַ</strong> (<em>kî-shibbir daltôt nĕḥōshet ûbĕrîḥê barzel giddêaʿ</em>, "For he has smashed the gates of bronze and snapped the iron bars!") — the <em>kî</em>-clause explaining how the rescue happened. <em>Daltôt nĕḥōshet</em>: the bronze/copper gates (the gates of the ancient dungeon or enemy city — Ps 9:13: "you who lift me from the gates of death"). Isa 45:2 uses this image for Cyrus: "I will break down the gates of bronze and cut through the bars of iron" (the Persian king as the LORD\'s instrument for releasing captives). The messianic application: the gates of death shattered (Matt 16:18: "the gates of Hades will not prevail").</p>',
    "17": '<p><strong>אֱוִלִים מִדֶּרֶךְ פִּשְׁעָם וּמֵעֲוֹנֹתֵיהֶם יִתְעַנּוּ</strong> (<em>ʾĕwîlîm midderek pishʿām ûmêʿăwōnōtêhem yitʿannû</em>, "Some were fools who made themselves sick by the path they chose, suffering because of their own sins!") — the third strophe (vv17-22): the sick. <em>ʾĔwîlîm</em>: fools (from <em>ʾĕwil</em>: the dense/thick fool who lacks moral sense — Prov 1:7; 10:8; distinct from <em>kĕsîl</em>/fool-by-choice). <em>Midderek pishʿām</em>: because of the path of their transgressions (<em>pesha</em>ʿ</em>: the covenant-breaking transgression, the deliberate rebellion — Isa 53:5: "he was wounded for our transgressions"). The sick suffer because of their own choices: the wisdom tradition connecting moral and physical health (though vv1-3\'s geographical gathering suggests this strophe has a broader application than individual punishment).</p>',
    "18": '<p><strong>כָּל-אֹכֶל תְּתַעֵב נַפְשָׁם וַיַּגִּיעוּ עַד-שַׁעֲרֵי מָוֶת</strong> (<em>kol-ʾōkhel tĕtaʿêb napshām wayyaggîʿû ʿad-shaʿărê māwet</em>, "Their soul could not bear any food, and they were approaching the very gates of death!") — <em>tĕtaʿêb</em>: it loathes, abominates (the absolute revulsion of the severely ill who cannot eat — the same word for the loathing of what is detestable in Lev 11:11,13). <em>Shaʿărê māwet</em>: the gates of death (death conceived as a city or underworld with gates — Ps 9:13; Job 38:17: "have the gates of death been shown to you?"; Isa 38:10: Hezekiah\'s lament). The gates not yet entered but imminent — the most extreme medical crisis the ancient world knew.</p>',
    "19": '<p>The third cry-and-rescue: <strong>וַיִּזְעֲקוּ אֶל-יְהוָה בַּצַּר לָהֶם מִמְּצוּקוֹתֵיהֶם יוֹשִׁיעֵם</strong> — identical to v13 (same strophe-formula). The repetition of the identical cry in the third strophe with a different affliction (sickness vs imprisonment) reinforces the psalm\'s universalism: the same cry works across all categories of suffering. The one who sent them into the prison of their folly (v17) is also the one who receives their cry and rescues.</p>',
    "20": '<p><strong>יִשְׁלַח דְּבָרוֹ וְיִרְפָּאֵם וִימַלֵּט מִשַּׁחִיתוֹתָם</strong> (<em>yishlah dĕbārô wĕyirpāʾêm wîmallêṭ mishshaḥîtôtām</em>, "He sent his word and healed them and pulled them back from the pit of destruction!") — <em>yishlah dĕbārô</em>: he sent his word (the active, personified word dispatched as a divine agent — Ps 33:6: "by the word of the LORD the heavens were made"; Isa 55:11: "my word shall not return to me empty"). The Word sent to heal anticipates John 1:1,14 and the healing ministry of the Word made flesh (Matt 8:16: "he cast out the spirits with a word and healed all who were sick"). <em>Shaḥîtôtām</em>: their pits/destructions (the plural of <em>shaḥat</em>: pit, corruption — used for both the physical grave and moral destruction — Ps 16:10: "you will not let your Holy One see corruption"; the resurrection connection).</p>',
    "21": '<p>The third refrain: <strong>יוֹדוּ לַיהוָה חַסְדּוֹ וְנִפְלְאוֹתָיו לִבְנֵי אָדָם</strong> — repeated verbatim. The fourfold structural use of this refrain is itself a theological act: the same praise-formula covers the rescue of wanderers, prisoners, sick, and sailors. No rescue is too small or too specific for the grand <em>ḥesed</em>; no sufferer falls outside the category of "children of man" for whom the wonders are done.</p>',
    "22": '<p><strong>וְיִזְבְּחוּ זִבְחֵי תוֹדָה וִיסַפְּרוּ מַעֲשָׂיו בְּרִנָּה</strong> (<em>wĕyizbĕḥû zibĕḥê tôdāh wîsappĕrû maʿăśāyw bĕrinnāh</em>, "Let them offer thanksgiving sacrifices and tell of his deeds with songs of joy!") — <em>zibĕḥê tôdāh</em>: thanksgiving sacrifices (Lev 7:12-15 — the specific offering of the <em>tôdāh</em> feast, eaten the same day, shared with family and the poor, accompanied by leavened and unleavened bread). The recovery from sickness calls for the most communal and joyful sacrifice. <em>Bĕrinnāh</em>: with ringing joy (the shout of glad exuberance — Ps 100:2). The rescue is not merely private: it becomes public proclamation (<em>sappĕrû maʿăśāyw</em>: narrate/recount his deeds — the word for the storytelling that preserves the memory of divine acts).</p>',
    "23": '<p><strong>יוֹרְדֵי הַיָּם בָּאֳנִיּוֹת עֹשֵׂי מְלָאכָה בְּמַיִם רַבִּים</strong> (<em>yôrĕdê hayyām bāʾŏniyyôt ʿōśê mĕlākhāh bĕmayim rabbîm</em>, "Some went down to the sea in ships, plying their trade on the wide and open sea!") — the fourth strophe (vv23-32): the sailors. <em>Yōrĕdê hayyām</em>: those who go down to the sea (the idiom for seafaring — "going down" because ships were launched from harbor to the lower sea-surface). <em>ʿŌśê mĕlākhāh</em>: doing their work/trade (the word <em>mĕlākhāh</em> covers both skilled craftsmanship and occupational work — used for the work of the tabernacle builders). <em>Bĕmayim rabbîm</em>: in the great waters (the sea as the <em>mayim rabbîm</em> of Ps 29:3; 93:4 — the cosmic chaos-waters that only YHWH controls).</p>',
    "24": '<p><strong>הֵמָּה רָאוּ מַעֲשֵׂי יְהוָה וְנִפְלְאוֹתָיו בִּמְצוּלָה</strong> (<em>hêmmāh rāʾû maʿăśê yĕhwāh wĕnipĕlĕʾōtāyw bimĕṣûlāh</em>, "They witnessed what the LORD does — his wonders in the depths!") — <em>maʿăśê yĕhwāh</em>: the works of the LORD (the acts of creation and sustaining — Ps 8:3; 19:1; 104:24). <em>Bimĕṣûlāh</em>: in the deep (the abyss of the ocean — Exod 15:5: "they sank into the depths like a stone"; Ps 69:2,15: the deep waters). The sailors are involuntary witnesses to the divine power in the most fearsome natural environment.</p>',
    "25": '<p><strong>וַיֹּאמֶר וַיַּעֲמֵד רוּחַ סְעָרָה וַתְּרוֹמֵם גַּלָּיו</strong> (<em>wayyōʾmer wayyaʿămêd rûaḥ sĕʿārāh wattĕrômêm gallāyw</em>, "He spoke and a storm-wind rose, whipping the sea into waves!") — <em>wayyōʾmer</em>: "and he said/spoke" — the bare divine speech as the cause of the storm (as in Gen 1: God speaks and things happen). <em>Rûaḥ sĕʿārāh</em>: a storm-wind (the same compound in Job 38:1; Ezek 1:4 — the divine storm from which God speaks). <em>Wattĕrômêm gallāyw</em>: and it lifted up its waves (the storm raising the sea into towering waves — Job 38:8-11: "who shut in the sea with doors?"). The storm is directly commanded by God and directly stilled by him in v29 — the episode of Jonah 1 and the disciples\' storm (Matt 8:23-27; Mark 4:35-41) are explicitly designed as fulfillments of this pattern.</p>',
    "26": '<p><strong>יַעֲלוּ שָׁמַיִם יֵרְדוּ תְהוֹמוֹת נַפְשָׁם בְּרָעָה תִתְמוֹגָג</strong> (<em>yaʿălû shāmayim yêrĕdû tĕhômôt napshām bĕrāʿāh titmmôgāg</em>, "They heaved up to the sky and plunged back down to the depths; their soul was melting away in terror!") — the graphic description of being tossed in a storm from the sailors\' perspective: sky one moment, abyss the next. <em>Tĕhômôt</em>: the deeps/tehom (Gen 1:2 — the primordial deep; Ps 77:16; 104:6). <em>Napshām bĕrāʿāh titmmôgāg</em>: "their soul melted away in their trouble" (<em>māgag</em>: to melt, to dissolve — Josh 2:11: Rahab says "our hearts melted" at Israel\'s approach). The physical motion (sky/depths) produces psychological dissolution.</p>',
    "27": '<p><strong>יָחוֹגּוּ וְיָנוּעוּ כַּשִּׁכּוֹר וְכָל-חָכְמָתָם תִּתְבַּלָּע</strong> (<em>yāḥôggû wĕyānûʿû kashshikkôr wĕkhol-ḥokhmātām titbāllāʿ</em>, "They lurched and stumbled like drunken men, and all their skill/wisdom was consumed!") — <em>yāḥôggû</em>: to reel, to stagger (from <em>ḥāgag</em>: the circular festival dance; here the uncontrolled staggering of a drunk or seasick man). <em>ḥokhmātām titbāllāʿ</em>: "all their wisdom was swallowed up" (<em>bālaʿ</em>: to swallow — Num 16:30-32: the earth opened and swallowed Korah\'s company; Exod 7:12: Aaron\'s staff swallowed the magicians\' staffs). The sailors\' skill and wisdom — the very things that qualified them to work "in great waters" (v23) — are swallowed by the chaos. Human competence exhausted; the cry (v28) becomes the only remaining option.</p>',
    "28": '<p>The fourth cry: <strong>וַיִּצְעֲקוּ אֶל-יְהוָה בַּצַּר לָהֶם וּמִמְּצוּקֹתֵיהֶם יוֹצִיאֵם</strong> (<em>wayyiṣʿăqû ʾel-yĕhwāh baṣṣar lāhem ûmimmĕṣûqōtêhem yôṣîʾêm</em>) — the fourth occurrence of the cry-rescue pattern, now using <em>yôṣîʾ</em> (he brought out — the Exodus verb of vv13-14). The cry comes after all human competence is exhausted (v27: wisdom swallowed). The pattern is deliberately structured: rescue does not come until all self-reliance is eliminated.</p>',
    "29": '<p><strong>יָקֵם סְעָרָה לִדְמָמָה וַיֶּחֱשׁוּ גַּלֵּיהֶם</strong> (<em>yāqêm sĕʿārāh lîdĕmāmāh wayyeḥĕshû gallêhem</em>, "He calmed the storm to a stillness, and the waves fell silent!") — <em>yāqêm sĕʿārāh lîdĕmāmāh</em>: "he raised the storm to a stillness" — the unusual idiom: the storm is "raised/established" (<em>qûm</em>) into (<em>lĕ</em>) stillness (<em>dĕmāmāh</em>). The same God who said "he spoke and a storm-wind rose" (v25) now speaks the storm into silence. <em>Dĕmāmāh</em>: the stillness, hush (1 Kgs 19:12: the "still small voice" — literally "voice of fine/thin silence" — <em>qôl dĕmāmāh daqqāh</em> — after the storm). Mark 4:39: "he rebuked the wind and said to the sea, \'Peace! Be still!\' And the wind ceased and there was a great calm."</p>',
    "30": '<p><strong>וַיִּשְׂמְחוּ כִי-יִשְׁתֹּקוּ וַיַּנְחֵם אֶל-מְחוֹז חֶפְצָם</strong> (<em>wayyiśmĕḥû kî-yishtōqû wayyanhêm ʾel-mĕḥôz ḥepṣām</em>, "They rejoiced as the sea grew calm, and he guided them into the harbor they had longed for!") — <em>mĕḥôz ḥepṣām</em>: the harbor of their longing/desire (a hapax — <em>mĕḥôz</em> appears nowhere else in the Hebrew Bible; <em>ḥêpeṣ</em>: delight, desire — the harbor they most wanted to reach). The rescue is not merely survival but the attainment of the original goal: the sailors set out to reach a destination (v23: working their trade) and the rescue brings them exactly there. Grace restores the original design.</p>',
    "31": '<p>The fourth and final refrain: <strong>יוֹדוּ לַיהוָה חַסְדּוֹ וְנִפְלְאוֹתָיו לִבְנֵי אָדָם</strong> — the last of the fourfold liturgical punctuation. Having covered desert wanderers, prisoners, sick, and sailors — the full human range of suffering — the psalm now turns in vv32-43 to a wisdom epilogue that interprets the fourfold pattern cosmically.</p>',
    "32": '<p><strong>וִירוֹמְמוּהוּ בִּקְהַל-עָם וּבְמוֹשַׁב זְקֵנִים יְהַלְלוּהוּ</strong> (<em>wîrômĕmûhû biqhal-ʿām ûbĕmôshab zĕqênîm yĕhallĕlûhû</em>, "Let them lift up his name in the great assembly and honor him in the council of the elders!") — the public dimension of rescue: the worship of the individual rescued is to be proclaimed <em>biqhal-ʿām</em> (in the congregation of the people — the full covenant assembly). <em>Môshab zĕqênîm</em>: the session of the elders (the judicial and leadership council — the equivalent of the city-gate assembly). Rescue generates testimony; testimony generates corporate praise. The fourfold rescue is not complete until it reaches the congregational gathering.</p>',
    "33": '<p><strong>יָשֵׂם נְהָרוֹת לְמִדְבָּר וּמֹצָאֵי מַיִם לְצִמָּאוֹן</strong> (<em>yāśêm nĕhārôt lĕmidbar ûmōṣāʾê mayim lĕṣimmāʾôn</em>, "He turns rivers into desert and springs of water into parched ground!") — the wisdom epilogue begins (vv33-43): the cosmic pattern of divine reversal. God can turn fertility into barrenness. <em>Nĕhārôt lĕmidbar</em>: rivers into wilderness (Isa 50:2: "I rebuke the sea and make it dry"; Ps 66:6). The productive river system (civilization\'s lifeblood) made into trackless desert. The pattern establishes divine sovereignty over both agricultural fertility and barrenness.</p>',
    "34": '<p><strong>אֶרֶץ פְּרִי לִמְלֵחָה מֵרָעַת יֹשְׁבֵי בָהּ</strong> (<em>ʾereṣ pĕrî limlêḥāh mêrāʿat yōshĕbê bāh</em>, "fertile land into a barren salt flat — for the wickedness of those who live there!") — <em>ʾereṣ pĕrî limlêḥāh</em>: the land of fruit/produce into salt/salt flat. <em>Mĕlêḥāh</em>: saltland (Gen 14:3: the Salt Sea; Deut 29:23: the divine curse makes the land "like Sodom and Gomorrah... sulphur and salt, burned-out"; Zeph 2:9: Moab like Sodom). The connection to Sodom is explicit: moral wickedness produces geographic desolation. This is the positive analogue of the cursed ground (Gen 3:17-19).</p>',
    "35": '<p><strong>יָשֵׂם מִדְבָּר לַאֲגַם-מַיִם וְאֶרֶץ צִיָּה לְמֹצָאֵי מָיִם</strong> (<em>yāśêm midbar laʾăgam-mayim wĕʾereṣ ṣiyyāh lĕmōṣāʾê māyim</em>, "But he can also turn the desert into pools of water and dry ground into flowing springs!") — the reversal of vv33-34: what God can make barren, he can also make fertile. <em>Midbar laʾăgam-mayim</em>: the wilderness into a pool/lake (Isa 41:18: "I will make the wilderness a pool of water and the dry land springs of water"). The same sovereign power that judges wickedness with barrenness also rescues the hungry with fertility (Isa 35:1-7: the messianic transformation of the desert into a garden).</p>',
    "36": '<p><strong>וַיּוֹשֶׁב שָׁם רְעֵבִים וַיְכוֹנְנוּ עִיר מוֹשָׁב</strong> (<em>wayyôsheb shām rĕʿêbîm waykônĕnû ʿîr môshāb</em>, "He brings the hungry to live there, and they build a city to call home!") — the same vocabulary as v4: the wanderers who found "no road to a city where they could live" (<em>ʿîr môshāb</em>) now build one in the transformed wilderness. The first strophe\'s rescue (vv4-9) is re-enacted at the cosmic/agricultural level: God turns the desert that the wanderers could not cross into the very city they could not find. The divine reversal is not abstract but creates human habitation.</p>',
    "37": '<p><strong>וַיִּזְרְעוּ שָׂדוֹת וַיִּטְּעוּ כְרָמִים וַיַּעֲשׂוּ פְּרִי תְבוּאָה</strong> (<em>wayyizrĕʿû śādôt wayyiṭṭĕʿû kĕrāmîm wayyaʿăśû pĕrî tĕbûʾāh</em>, "They plant fields and vineyards that bring in an abundant crop!") — the agricultural acts that civilization requires: planting fields and vineyards (the grain and fruit that together represent food and drink — Deut 8:8). <em>Pĕrî tĕbûʾāh</em>: fruit of produce/harvest (the abundant yield that exceeds subsistence). The newly settled community creates the agricultural civilization that was impossible in the desert of v4. Creation\'s mandate (Gen 1:28: "be fruitful and multiply") fulfilled in the transformed wilderness.</p>',
    "38": '<p><strong>וַיְבָרְכֵם וַיִּרְבּוּ מְאֹד וּבְהֶמְתָּם לֹא יַמְעִיט</strong> (<em>waybārĕkhêm wayyirbû mĕʾōd ûbĕhemtām lōʾ yamʿîṭ</em>, "He blesses them and they grow in number, and he keeps their herds from shrinking!") — <em>waybārĕkhêm wayyirbû mĕʾōd</em>: "he blessed them and they multiplied greatly" — the creation blessing of Gen 1:22,28 ("be fruitful and multiply") enacted in historical time. <em>Ûbĕhemtām lōʾ yamʿîṭ</em>: "and their cattle he does not diminish" — the livestock as the measure of agricultural blessing (Gen 13:2; Deut 7:13-14). Divine blessing expressed in demographic and pastoral abundance.</p>',
    "39": '<p><strong>וַיִּמְעֲטוּ וַיָּשֹׁחוּ מֵעֹצֶר רָעָה וְיָגוֹן</strong> (<em>wayyimʿăṭû wayyāshōḥû mêʿōṣer rāʿāh wĕyāgôn</em>, "But when they are cut down and humbled through oppression, calamity, and grief!") — the reversal returns: the same community that multiplied (v38) can be reduced (<em>mĕʿaṭ</em>: to be few/small — Lev 26:22: "your animals will be few"). <em>ʿŌṣer</em>: oppression, constraint; <em>rāʿāh</em>: calamity/evil; <em>yāgôn</em>: grief/sorrow. The three negative forces that collapse the abundance of vv36-38. The historical pattern: the blessing of settlement followed by oppression (Judges cycle).</p>',
    "40": '<p><strong>שֹׁפֵךְ בּוּז עַל-נְדִיבִים וַיַּתְעֵם בְּתֹהוּ לֹא-דָרֶךְ</strong> (<em>shōpêkh bûz ʿal-nĕdîbîm wayyatʿêm bĕtōhû lōʾ-dārek</em>, "he pours contempt on rulers and sends them wandering in pathless deserts!") — <em>bûz</em>: contempt, dishonor (the opposite of <em>kābôd</em>/honor — Prov 12:8; the divine valuation applied inversely). <em>ʿAl-nĕdîbîm</em>: on princes/nobles/generous ones — those who had status and power. <em>Wayyatʿêm bĕtōhû lōʾ-dārek</em>: he makes them wander in pathless wasteland (<em>tōhû</em>: the same formlessness-waste as Gen 1:2 and v4). The leaders who built the city (v36) are returned to the desert by the same divine sovereignty that created the city. Job 12:24 quotes this verse almost verbatim.</p>',
    "41": '<p><strong>וַיְשַׂגֵּב אֶבְיוֹן מֵעוֹנִי וַיָּשֶׂם כַּצֹּאן מִשְׁפָּחוֹת</strong> (<em>wayyĕśaggêb ʾebyôn mêʿônî wayyāśem kaṣṣōʾn mishpāḥôt</em>, "but he raises the poor person up from their misery and makes their family grow like a flock!") — the simultaneous reversal: while the nobles wander in the wasteland (v40), the poor person is elevated. <em>ʾEbyôn</em>: the desperately poor/needy. <em>Śāgab</em> (piel: to set on high, to lift to safety — Ps 59:1; 91:14; Prov 29:25: "whoever trusts in the LORD is kept safe"). <em>Kaṣṣōʾn mishpāḥôt</em>: like a flock, families (from the shepherd-flock image of v3\'s gathering). The divine reversal runs simultaneously: nobles down, poor up. Hannah\'s song (1 Sam 2:4-8) and the Magnificat (Luke 1:51-53) are the clearest developments of this pattern.</p>',
    "42": '<p><strong>יִרְאוּ יְשָׁרִים וְיִשְׂמָחוּ וְכָל-עַוְלָה קָפְצָה פִּיהָ</strong> (<em>yirʾû yĕshārîm wĕyiśmāḥû wĕkhol-ʿawlāh qāpĕṣāh pîhāh</em>, "The righteous see all this and rejoice, while every mouth of wickedness is stopped!") — <em>yĕshārîm</em>: the upright/straight ones (those whose inner orientation is aligned with the divine character — Ps 33:1; 97:11). Their joy is epistemological: they see and understand what is happening in the divine reversal. <em>ʿAwlāh qāpĕṣāh pîhāh</em>: "wickedness stops its mouth" (<em>qāpaṣ</em>: to close suddenly, to snap shut — the mouth of the wicked has no more to say when the divine vindication is plain). Rom 3:19: "every mouth may be stopped and the whole world held accountable to God."</p>',
    "43": '<p><strong>מִי-חָכָם וְיִשְׁמָר-אֵלֶּה וְיִתְבּוֹנְנוּ חַסְדֵי יְהוָה</strong> (<em>mî-ḥākhām wĕyishmār-ʾêlleh wĕyitbônĕnû ḥasdê yĕhwāh</em>, "Let those who are wise take note of all this and reflect carefully on the steadfast love of the LORD!") — the wisdom epilogue\'s climactic verse. <em>Mî-ḥākhām</em>: "who is wise?" — the rhetorical summons to wisdom (Hos 14:9: "who is wise? Let them understand these things" — the virtually identical verse at the end of Hosea; Eccl 8:1: "who is like the wise man?"). <em>Wĕyishmār-ʾêlleh</em>: and will keep/observe these things (the word <em>shāmar</em> covers both watching carefully and keeping as commandment). <em>Wĕyitbônĕnû ḥasdê yĕhwāh</em>: and ponder/understand the steadfast loves of the LORD (<em>ḥasdê</em>: the plural of <em>ḥesed</em> — the many expressions of the one covenant character). The whole psalm was a demonstration of the divine <em>ḥasdê</em> in action; wisdom is the capacity to see and understand what the four strophes have displayed.</p>',
  },
  "108": {
    "1": '<p>Psalm 108 is a deliberate composite: vv1-5 = Ps 57:7-11 and vv6-13 = Ps 60:5-12. The combination is not accidental — it pairs the individual\'s confident praise (Ps 57, written by David in a cave fleeing Saul) with the national lament over defeat (Ps 60, written after a battle). <strong>נָכוֹן לִבִּי אֱלֹהִים אָשִׁירָה וַאֲזַמְּרָה אַף-כְּבוֹדִי</strong> (<em>nākhôn libbî ʾĕlōhîm ʾāshîrāh waʾăzammĕrāh ʾap-kĕbôdî</em>, "My heart is ready/established, O God; I will sing and praise you with all my glory!") — <em>nākhôn libbî</em>: my heart is established/firm (<em>kônen</em>: the word for permanent establishment — Ps 57:7: the same opening). <em>ʾAp-kĕbôdî</em>: yes, even my glory (the <em>kābôd</em> — the weightiest part of the person, the soul-identity — Ps 7:5; 30:12: "that my glory may sing to you and not be silent").</p>',
    "2": '<p><strong>עוּרָה הַנֵּבֶל וְכִנּוֹר אָעִירָה שָּׁחַר</strong> (<em>ʿûrāh hannêbel wĕkhinnôr ʾāʿîrāh shaḥar</em>, "Awake, harp and lyre! I will be the one to rouse the dawn!") — <em>ʾāʿîrāh shaḥar</em>: "I will awaken/arouse the dawn" — a remarkable reversal of the normal order where the dawn awakens the sleeper. The worshipper rises before dawn to worship, and by singing awakens the dawn itself. The commitment to praise is so fierce that it precedes the most natural orientation-marker of the day (Ps 57:8: the same phrase). <em>Nêbel wĕkhinnôr</em>: the harp and lyre (the large and small stringed instruments of the temple praise ensemble).</p>',
    "3": '<p><strong>אוֹדְךָ בָעַמִּים יְהוָה וַאֲזַמֶּרְךָ בַּלְאֻמִּים</strong> (<em>ʾôdĕkā bāʿammîm yĕhwāh waʾăzammĕrekā ballĕʾummîm</em>, "I will praise you, O LORD, among all peoples and sing your praises among the nations!") — the universal scope of David\'s intended praise: not in the congregation alone but <em>bāʿammîm</em> (among the peoples) and <em>ballĕʾummîm</em> (among the nations). Paul cites the parallel verse Ps 57:9 in Rom 15:9: "I will praise you among the Gentiles" — demonstrating that the inclusion of the Gentiles in the messianic age was anticipated in David\'s praise-intention.</p>',
    "4": '<p><strong>כִּי-גָדוֹל מֵעַל-שָׁמַיִם חַסְדֶּךָ וְעַד-שְׁחָקִים אֲמִתֶּךָ</strong> (<em>kî-gādôl mêʿal-shāmayim ḥasdekā wĕʿad-shĕḥāqîm ʾămittekā</em>, "For your steadfast love towers above the heavens, and your faithfulness reaches to the skies!") — the divine character measured against the largest things available for comparison: <em>ḥesed</em> (steadfast love) exceeds the heavens (<em>mêʿal-shāmayim</em>: above/beyond the sky); <em>ʾĕmet</em>/<em>ʾĕmûnāh</em> (faithfulness) reaches to the clouds (<em>shĕḥāqîm</em>: the clouds/upper atmosphere). The covenant attributes are literally unmeasurable — they exceed the largest spatial categories. Ps 57:10 has the same verse.</p>',
    "5": '<p><strong>רוּמָה עַל-שָׁמַיִם אֱלֹהִים וְעַל כָּל-הָאָרֶץ כְּבוֹדֶךָ</strong> (<em>rûmāh ʿal-shāmayim ʾĕlōhîm wĕʿal kol-hāʾāreṣ kĕbôdekā</em>, "Be lifted high above the heavens, O God! Let your glory fill the whole earth!") — the petition: let the divine <em>kābôd</em> that already exceeds the heavens (v4) be manifest so that the whole earth sees it. <em>Rûmāh</em>: be exalted/raised (the qal imperative — a request to God to make his own exaltation visible). <em>Wĕʿal kol-hāʾāreṣ kĕbôdekā</em>: and over all the earth your glory. The same prayer as Isa 6:3 (the whole earth is full of his glory) asked to be realized in historical experience.</p>',
    "6": '<p><strong>לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי</strong> (<em>lĕmaʿan yêḥālĕṣûn yĕdîdêkā hôshîʿāh yĕmînĕkā waʿănênî</em>, "Save your beloved ones — rescue us by your mighty hand and answer our prayer!") — <em>yĕdîdêkā</em>: your beloved/loved ones (<em>yādîd</em>: beloved — the same root as David\'s alternate name Jedidiah — 2 Sam 12:25; Ps 45:1: the Beloved King; Ps 84:1: the lovely/beloved dwelling). The beloved community cries for rescue. <em>Hôshîʿāh yĕmînĕkā</em>: save with your right hand — the same right hand that will "make enemies a footstool" (Ps 110:1).</p>',
    "7": '<p><strong>אֱלֹהִים דִּבֶּר בְּקָדְשׁוֹ אֶעְלֹזָה אֲחַלְּקָה שְׁכֶם וְעֵמֶק סֻכּוֹת אֲמַדֵּד</strong> (<em>ʾĕlōhîm dibbêr bĕqōdshô ʾeʿlōzāh ʾăḥallĕqāh shĕkhem wĕʿêmeq sukkôt ʾămaddêd</em>, "God has spoken from his holy place: \'I will celebrate; I will apportion Shechem and measure out the valley of Succoth.\'") — the divine oracle begins: <em>bĕqōdshô</em> (from his holiness/holy place — the sanctuary or the divine character of holiness from which the oracle comes). <em>ʾĔʿlōzāh</em>: I will exult (the victorious king\'s triumph shout). Shechem (central Canaan, near Nablus) and Succoth (in Transjordan) are named as the divine king\'s domains — territories on both sides of the Jordan representing the full extent of the promised land.</p>',
    "8": '<p><strong>לִי גִלְעָד לִי מְנַשֶּׁה וְאֶפְרַיִם מָעוֹז רֹאשִׁי יְהוּדָה מְחֹקְקִי</strong> (<em>lî gilʿād lî mĕnashsheh wĕʾeprayim māʿôz rōʾshî yĕhûdāh mĕḥōqĕqî</em>, "Gilead belongs to me; Manasseh belongs to me; Ephraim is the helmet on my head; Judah is my royal scepter!") — the divine king\'s territorial sovereignty declared through possession formulae. <em>Māʿôz rōʾshî</em>: the strength/fortress of my head (the helmet — Ephraim as the military power protecting the royal head). <em>Mĕḥōqĕqî</em>: my lawgiver/scepter (Judah as the seat of royal authority — Gen 49:10: "the scepter shall not depart from Judah... until tribute comes to him"). The tribal territories become metaphors for the divine king\'s own equipment.</p>',
    "9": '<p><strong>מוֹאָב סִיר רַחְצִי עַל-אֱדוֹם אַשְׁלִיךְ נַעֲלִי עֲלֵי-פְלֶשֶׁת אֶתְרוֹעָע</strong> (<em>môʾāb sîr raḥṣî ʿal-ʾĕdôm ʾashlîk naʿălî ʿălê-pĕleshet ʾetroʿāʿ</em>, "Moab is my washbasin; over Edom I toss my sandal; over Philistia I raise a victory shout!") — the three traditional enemies of Israel subjected to symbolic gestures of contempt. <em>Sîr raḥṣî</em>: washbasin/pot for washing (the vessel used to wash feet — a menial, domestic image: Moab the great neighboring kingdom reduced to a servant\'s foot-washing bowl). <em>ʾAshlîk naʿălî</em>: I throw my sandal (to throw a sandal was either an act of possession-taking — Ruth 4:7-8 — or contemptuous dismissal — "this is only worth the throw of a shoe"). Philistia receives the victory-shout of the conquering warrior.</p>',
    "10": '<p><strong>מִי יֹבִלֵנִי עִיר מִבְצָר מִי נָחַנִי עַד-אֱדוֹם</strong> (<em>mî yôbilênî ʿîr mibṣār mî nāḥanî ʿad-ʾĕdôm</em>, "Who will take me into the strong, walled city? Who will guide me all the way to Edom?") — the transition from divine oracle (vv7-9) back to human prayer: if God has declared these territories his, who will actually lead the human king into them? <em>ʿÎr mibṣār</em>: the fortified city (the inaccessible stronghold — Ps 60:9: the same question). The gap between the divine promise and the human reality creates the space of petition.</p>',
    "11": '<p><strong>הֲלֹא אַתָּה אֱלֹהִים זְנַחְתָּנוּ וְלֹא-תֵצֵא אֱלֹהִים בְּצִבְאוֹתֵינוּ</strong> (<em>hălōʾ ʾattāh ʾĕlōhîm zĕnaḥtānû wĕlōʾ-têṣêʾ ʾĕlōhîm bĕṣibʾōtênû</em>, "God, have you not turned your back on us? Why do you no longer march out with our armies?") — <em>zānah</em>: to reject, to spurn (the covenant-abandonment word — Ps 44:9,23; Lam 3:31: "the Lord will not cast off forever"). <em>Lōʾ-têṣêʾ bĕṣibʾōtênû</em>: you do not go out with our armies (God as the divine warrior who marched at the head of Israel\'s army — Exod 13:21; Judg 4:14; 2 Sam 5:24). The divine oracle of vv7-9 is believed — the sovereignty of God over the nations is confessed — but the present military reality contradicts it. The psalm holds the tension without resolving it.</p>',
    "12": '<p><strong>הָבָה-לָּנוּ עֶזְרָת מִצָּר וְשָׁוְא תְּשׁוּעַת אָדָם</strong> (<em>hābāh-llānû ʿezrāt miṣṣār wĕshāwĕʾ tĕshûʿat ʾādām</em>, "Come to our aid against the enemy — human help amounts to nothing!") — <em>shāwĕʾ tĕshûʿat ʾādām</em>: "vain/emptiness is the salvation of man" (<em>shāwĕʾ</em>: emptiness, vanity — the word for the name taken in vain, Exod 20:7; the vanity of Ecclesiastes is <em>hebel</em> but <em>shāwĕʾ</em> denotes deliberate falseness/uselessness). Ps 60:11: the identical phrase. Human military assistance is not merely insufficient but fundamentally unreliable — the word "vain" suggests something that promises but does not deliver. The petition for divine help is thus grounded in the acknowledged bankruptcy of human alternatives.</p>',
    "13": '<p><strong>בֵּאלֹהִים נַעֲשֶׂה-חָיִל וְהוּא יָבוּס צָרֵינוּ</strong> (<em>bêʾlōhîm naʿăśeh-ḥāyil wĕhûʾ yābûs ṣārênû</em>, "With God we will fight with courage, for he is the one who will crush our enemies underfoot!") — the psalm\'s final confidence: <em>bêʾlōhîm naʿăśeh-ḥāyil</em> (with/through God we will do valiantly — <em>ḥayil</em>: valor, military strength). Not instead of human action but through human action empowered by God. <em>Yābûs ṣārênû</em>: "he will trample our adversaries" (<em>bûs</em>: to tread underfoot — Ps 44:5; Mic 7:19; Mal 4:3). Ps 60:12: the identical confidence. The composite psalm ends where it must: not in human calculation but in divine victory.</p>',
  },
  "109": {
    "1": '<p>Psalm 109 is the most extended imprecatory psalm, attributed to David. Its central interpretive question: are vv6-20 (1) the Psalmist\'s curses against his enemies, or (2) a quotation of what the enemies have said against the Psalmist? The singular in v6 (after the plurals of vv2-5) and the shift back in v20 ("let this be the reward of my accusers") support reading (1), but the extended length and specificity of the curses lend plausibility to (2). <strong>אֱלֹהֵי תְהִלָּתִי אַל-תֶּחֱרַשׁ</strong> (<em>ʾĕlōhê tĕhillātî ʾal-teḥĕrash</em>, "O God — the one I praise — do not be silent!") — <em>ʾĕlōhê tĕhillātî</em>: "God of my praise" — the divine identity declared as the subject of the Psalmist\'s ongoing praise (Ps 22:25: "my praise is from you"; Deut 10:21: "he is your praise"). To address God as "God of my praise" while being attacked by enemies is the psalm\'s opening paradox: the God who is praised has been silent. <em>ʾAl-teḥĕrash</em>: do not be deaf/silent (Ps 28:1; 83:1: the same plea).</p>',
    "2": '<p><strong>כִּי פִי רָשָׁע וּפִי-מִרְמָה עָלַי פָּתָחוּ</strong> (<em>kî pî rāshāʿ ûpî-mirmāh ʿālay pātāḥû</em>, "For the mouths of the wicked and the treacherous are opened wide against me!") — <em>pî rāshāʿ</em>: the mouth of the wicked (the instrument of the attack — not physical violence but verbal); <em>pî-mirmāh</em>: the mouth of deceit (<em>mirmāh</em>: deception, treachery — Ps 52:2-4). Two mouths opened against one person: the attack is verbal and coordinated. <strong>דִּבְּרוּ אִתִּי לְשׁוֹן שָׁקֶר</strong> (<em>dibbĕrû ʾittî lĕshôn shāqer</em>, "they have spoken against me with a lying tongue!") — <em>lĕshôn shāqer</em>: a lying tongue (Prov 6:17: one of the seven things YHWH hates). The conflict is fundamentally forensic/verbal: the Psalmist is being accused with false words.</p>',
    "3": '<p><strong>וְדִבְרֵי שִׂנְאָה סְבָבוּנִי וַיִּלָּחֲמוּנִי חִנָּם</strong> (<em>wĕdibrê sinʾāh sĕbābûnî wayyillāḥăṣûnî ḥinnām</em>, "They encircle me with hateful words and fight against me for no reason!") — <em>dibrê sinʾāh sĕbābûnî</em>: words of hatred have surrounded me (the encirclement of hostile speech — Ps 22:12,16: "bulls surround me"). <em>Wayyillāḥăṣûnî ḥinnām</em>: they attack/fight against me without cause (<em>ḥinnām</em>: without reason, freely, for nothing — Ps 35:7,19; 69:4; John 15:25: "they hated me without reason" quotes the <em>ḥinnām</em> of the Psalms). The groundlessness of the hatred makes it more unbearable and more recognizably satanic in character.</p>',
    "4": '<p><strong>תַּחַת-אַהֲבָתִי יִשְׂטְנוּנִי וַאֲנִי תְפִלָּה</strong> (<em>taḥat-ʾahăbātî yiśṭĕnûnî waʾănî tĕpillāh</em>, "In exchange for my love they have become my adversaries, though I am prayer itself!") — <em>taḥat-ʾahăbātî</em>: in place of/in return for my love (the return of hatred for love — Ps 35:12: "they repaid me evil for good"). <em>Yiśṭĕnûnî</em>: they act as my <em>śāṭān</em> — the same root as the legal-court accuser and the cosmic adversary. <em>Waʾănî tĕpillāh</em>: "but I am prayer" — perhaps the most concentrated self-description in the Psalter: the Psalmist does not merely say "I pray"; he says his entire existence is prayer. In response to the verbal attack, prayer is his only posture and his total identity.</p>',
    "5": '<p><strong>וַיָּשִׂימוּ עָלַי רָעָה תַּחַת טוֹבָה וְשִׂנְאָה תַּחַת אַהֲבָתִי</strong> (<em>wayyāśîmû ʿālay rāʿāh taḥat ṭôbāh wĕsinʾāh taḥat ʾahăbātî</em>, "They have paid me back evil for good and hatred in place of my love!") — the double inversion restated with parallelism: evil for good, hatred for love. The chiastic relationship between love (v4) and hatred (vv4-5) is the psalm\'s moral center: the Psalmist loved, was attacked; the enemies hated, had been loved. This sets up the question of whether the imprecation that follows is justice or excess. Prov 17:13: "if anyone returns evil for good, evil will not depart from their house."</p>',
    "6": '<p><strong>הַפְקֵד עָלָיו רָשָׁע וְשָׂטָן יַעֲמֹד עַל-יְמִינוֹ</strong> (<em>hapqêd ʿālāyw rāshāʿ wĕśāṭān yaʿămōd ʿal-yĕmînô</em>, "Set a wicked man to judge him; let an accuser take his place at his right hand!") — v6 begins the disputed section (vv6-20). The singular "him" after the plural "they" of vv2-5 suggests either a primary ringleader is targeted or the whole section is a quotation of what the enemies said about the Psalmist. <em>Śāṭān</em>: the legal-court accuser (the noun <em>śāṭān</em> in its pre-apocalyptic meaning: a human or divine adversary who makes accusations — Job 1-2; Zech 3:1-2). <em>ʿAl-yĕmînô</em>: at his right hand (the place of the legal advocate — Ps 16:8; 110:5; Ps 109:31 inverts this: God stands at the right hand of the poor). The accuser usurps the advocate\'s position.</p>',
    "7": '<p><strong>בְּהִשָּׁפְטוֹ יֵצֵא רָשָׁע וּתְפִלָּתוֹ תִּהְיֶה לַחֲטָאָה</strong> (<em>bĕhishshāpĕṭô yêṣêʾ rāshāʿ ûtĕpillātô tihyeh laḥăṭāʾāh</em>, "When he faces judgment, let him be condemned; let even his prayer be turned against him!") — <em>yêṣêʾ rāshāʿ</em>: "may he come out guilty" (the verdict in the divine court: <em>rāshāʿ</em> as the guilty verdict, as opposed to <em>ṣaddîq</em>/righteous). <em>Ûtĕpillātô tihyeh laḥăṭāʾāh</em>: "and let his prayer become sin" — the most terrifying of all the imprecations: not merely the prayers unanswered but the prayers themselves becoming the source of condemnation. Prayer turned into iniquity is what happens when one who has rejected God\'s counsel continues to pray as if the relationship is intact (Prov 28:9: "if one turns away from hearing the law, even his prayer is an abomination").</p>',
    "8": '<p><strong>יִהְיוּ-יָמָיו מְעַטִּים פְּקֻדָּתוֹ יִקַּח אַחֵר</strong> (<em>yihyû-yāmāyw mĕʿaṭṭîm pĕquddātô yiqqaḥ ʾaḥêr</em>, "Let his life be cut short; let someone else take his position!") — <em>yimĕʿaṭṭîm</em>: let his days be few (the opposite of the blessing of long life — Ps 91:16). <em>Pĕquddātô yiqqaḥ ʾaḥêr</em>: "let another take his office/oversight" (<em>pĕquddāh</em>: appointment, office, oversight — from <em>pāqad</em>: to visit, to appoint). This verse is the one Peter quotes in Acts 1:20 of Judas Iscariot: "his office let another take" — the Greek <em>ἐπισκοπή</em> translates <em>pĕquddāh</em>. The apostolic vacancy is filled by citing the Davidic imprecation as prophetic of the betrayer\'s end and replacement.</p>',
    "9": '<p><strong>יִהְיוּ-בָנָיו יְתוֹמִים וְאִשְׁתּוֹ אַלְמָנָה</strong> (<em>yihyû-bānāyw yĕtômmîm wĕʾishtô ʾalmānāh</em>, "Let his children be left without a father and his wife become a widow!") — the most socially devastating consequence of a man\'s death in the ancient world: the widowed wife with no legal protector and the fatherless children exposed to exploitation. The Law specifically protected these groups (Exod 22:22-24; Deut 10:18; 14:29; 27:19) — their vulnerability made them objects of divine concern. The imprecation turns the enemy into the very social category his own wickedness (v16: "he hounded the poor and needy") exploited.</p>',
    "10": '<p><strong>וְנוֹעַ יָנוּעוּ בָנָיו וְשִׁאֵלוּ וְדָרְשׁוּ מֵחָרְבוֹתֵיהֶם</strong> (<em>wĕnôaʿ yānûʿû bānāyw wĕshiʾêlû wĕdārĕshû mêḥoorbôtêhem</em>, "Let his children wander and beg, searching for bread far from their ruined homes!") — <em>nôaʿ yānûʿû</em>: the doubled verb intensifies the wandering (the restless, directionless movement of the homeless — as Cain: Gen 4:12,14: "a fugitive and wanderer"). <em>ḥārbôtêhem</em>: their ruins (the destroyed house from which they must now search for food). The children must beg where the father once had power.</p>',
    "11": '<p><strong>יְנַקֵּשׁ נוֹשֶׁה לְכָל-אֲשֶׁר-לוֹ וְיָבֹזּוּ זָרִים יְגִיעוֹ</strong> (<em>yĕnaqqêsh nōsheh lĕkhol-ʾăsher-lô wĕyābōzzû zārîm yĕgîʿô</em>, "Let creditors take everything he owns; let foreigners carry off all he has worked for!") — <em>nōsheh</em>: the creditor (from <em>nāshāh</em>: to lend at interest — Deut 15:2; 24:11). The enemy who exploited the poor (v16) now faces the ultimate economic reversal: seized by the creditor, looted by foreigners. <em>Yĕgîʿô</em>: the product of his toil (all the labor-value he accumulated).</p>',
    "12": '<p><strong>אַל-יְהִי-לוֹ מֹשֵׁךְ חָסֶד וְאַל-יְהִי חוֹנֵן לִיתוֹמָיו</strong> (<em>ʾal-yĕhî-lô mōshêk ḥesed wĕʾal-yĕhî ḥônên lîtômmāyw</em>, "Let no one show him loyal kindness or take pity on the children he left behind!") — the social exclusion: <em>mōshêk ḥesed</em> (one who extends steadfast love — <em>māshak</em>: to draw out, to extend; <em>ḥesed</em>: the covenant loyalty that creates obligation to help). The refusal of <em>ḥesed</em> to the one who showed no <em>ḥesed</em> (v16) is the lex talionis of social obligation. <em>ḥônên lîtômmāyw</em>: one who is gracious to his orphans — even the children receive no grace, because the father\'s wickedness has exhausted the community\'s social capital toward his household.</p>',
    "13": '<p><strong>יְהִי-אַחֲרִיתוֹ לְהַכְרִית בְּדוֹר אַחֵר יִמַּח שְׁמָם</strong> (<em>yĕhî-ʾaḥărîtô lĕhakhrit bĕdôr ʾaḥêr yimmah shĕmām</em>, "Let his line come to an end; let his family name be wiped out in the next generation!") — <em>ʾaḥărît</em>: the latter end/posterity (the future generation that carries a family\'s name forward). <em>Lĕhakhrit</em>: to be cut off (<em>kārat</em>: the covenantal cutting-off — excision from Israel\'s community — Lev 17:10,14; the most severe covenantal sanction). <em>Yimmah shĕmām</em>: their name will be wiped out (<em>māḥāh</em>: to blot out — Exod 17:14: "I will utterly blot out the memory of Amalek"; Deut 9:14; 25:19). The ultimate fate the Psalmist of v107:43 calls wise people to observe is here invoked against the enemy.</p>',
    "14": '<p><strong>יִזָּכֵר עֲוֹן אֲבֹתָיו אֶל-יְהוָה וְחַטַּאת אִמּוֹ אַל-תִּמָּח</strong> (<em>yizzākêr ʿăwōn ʾăbōtāyw ʾel-yĕhwāh wĕḥaṭṭat ʾimmô ʾal-timmāḥ</em>, "Let the LORD keep his fathers\' guilt on record and never wipe out his mother\'s sin!") — the covenant principle of generational accountability (Exod 20:5: "visiting the iniquity of the fathers on the children to the third and fourth generation of those who hate me"). The Psalmist asks that the guilty man\'s family guilt remain on the divine ledger rather than be forgiven. The fathers\' <em>ʿāwōn</em> (iniquity) and the mother\'s <em>ḥaṭṭāʾt</em> (sin/sin-offering) — both formal covenant terms — are to remain unblotted.</p>',
    "15": '<p><strong>יִהְיוּ נֶגֶד-יְהוָה תָּמִיד וְיַכְרֵת מֵאֶרֶץ זִכְרָם</strong> (<em>yihyû neged-yĕhwāh tāmîd wĕyakhret mêʾereṣ zikhram</em>, "Let all those sins stand always before the LORD, until he wipes out their very memory from the earth!") — <em>neged-yĕhwāh tāmîd</em>: always before the LORD (the divine ledger never cleared — the guilt before the divine gaze without respite of forgiveness). <em>Wĕyakhret mêʾereṣ zikhram</em>: "so that he may cut off their memory from the earth" — <em>zikrām</em>: their remembrance/memorial (the opposite of the enduring name that the righteous receive — Ps 112:6: "the righteous will be remembered forever"). Memory cut off = the most complete form of judgment.</p>',
    "16": '<p><strong>יַעַן אֲשֶׁר לֹא זָכַר עֲשׂוֹת חָסֶד וַיִּרְדֹּף אִישׁ-עָנִי וְאֶבְיוֹן</strong> (<em>yaʿan ʾăsher lōʾ zākhar ʿăśôt ḥesed wayyirdōp ʾîsh-ʿānî wĕʾebyôn</em>, "For he never thought to show loyal kindness, but hounded the poor, the needy, and the brokenhearted to the point of killing them!") — <em>lōʾ zākhar ʿăśôt ḥesed</em>: he did not remember to do <em>ḥesed</em> (covenant-loyalty-in-action toward the vulnerable — Mic 6:8: "do justice, love kindness"). <em>Wayyirdōp ʾîsh-ʿānî wĕʾebyôn</em>: he pursued/hounded the poor and needy man. <em>Dākaʾ lêb</em> (in the full verse): the brokenhearted (Ps 34:18; 51:17: "a broken and contrite heart, O God, you will not despise"). The irony: he crushed the very people God specifically protects, which is why God specifically crushes him.</p>',
    "17": '<p><strong>וַיֶּאֱהַב קְלָלָה וַתְּבוֹאֵהוּ וְלֹא-חָפֵץ בִּבְרָכָה וַתִּרְחַק מִמֶּנּוּ</strong> (<em>wayyeʾĕhab qĕlālāh wattĕbôʾêhû wĕlōʾ-ḥāpêṣ bibrākhāh wattirḥaq mimmennu</em>, "He loved to curse — let curses come to him! He took no pleasure in blessing — let blessing stay far from him!") — the principle of moral gravity: what you love finds you. <em>ʾĀhab qĕlālāh</em>: he loved cursing (<em>qālal</em>: the root meaning to make light, to treat as contemptible, to curse). <em>Wĕlōʾ-ḥāpêṣ bibrākhāh</em>: he had no delight in blessing (the word <em>ḥāpêṣ</em> — delight — is the same word used for the LORD\'s delight in his own steadfast love, Ps 5:4; Isa 53:10). His choices have structured the universe of his reception: cursing-seeking finds cursing; blessing-rejecting cannot receive blessing.</p>',
    "18": '<p><strong>וַיִּלְבַּשׁ קְלָלָה כְּמַדּוֹ וַתָּבֹא כַמַּיִם בְּקִרְבּוֹ וְכַשֶּׁמֶן בְּעַצְמוֹתָיו</strong> (<em>wayyilbash qĕlālāh kĕmaddô wattābōʾ kammayim bĕqirbô wĕkashshemen bĕʿaṣmôtāyw</em>, "He wrapped himself in curses like a coat; let that curse seep into his body like water and into his bones like oil!") — the garment-of-curses image is uniquely powerful: cursing is not merely something he did but something he clothed himself with, making it his identity-garment. <em>Kammayim bĕqirbô</em>: like water into his inner being (water permeating the body — unstoppable absorption). <em>Kashshemen bĕʿaṣmôtāyw</em>: like oil into his bones (oil penetrating the deepest structural material — the ancient image of deep absorption). The curse, having been his voluntary garment, now soaks into his physiology.</p>',
    "19": '<p><strong>תְּהִי-לוֹ כְּבֶגֶד יַעְטֶה וּלְמֵזַח תָּמִיד יַחְגְּרֶהָ</strong> (<em>tĕhî-lô kĕbeged yaʿṭeh ûlĕmêzaḥ tāmîd yaḥgĕrehā</em>, "Let it cling to him like the clothing he wears, like a belt strapped on every single day!") — the curse as permanent daily clothing: the garment (<em>beged</em>) pulled on and the belt (<em>mêzaḥ</em>) cinched daily. <em>Tāmîd</em>: always, continually. If he chose cursing as his daily practice and identity, let his identity-garment be the curse itself — inseparable from him as the clothes he wears and the belt that defines his figure. The metaphor of garments recurs in the psalm (v18: the coat of curses; v29: the accusers draped in shame).</p>',
    "20": '<p><strong>זֹאת פְּעֻלַּת שֹׂטְנַי מֵאֵת יְהוָה וְהַדֹּבְרִים רָע עַל-נַפְשִׁי</strong> (<em>zōʾt pĕʿullat śōṭĕnay mêʾêt yĕhwāh wĕhaddōbĕrîm rāʿ ʿal-napshî</em>, "Let the LORD repay my accusers with all of this — those who speak evil against me!") — <em>śōṭĕnay</em>: my adversaries/accusers (<em>śāṭān</em> turned into a verb-noun for the human adversaries — the same root as v6). This verse returns to the perspective of the Psalmist addressing God about his enemies (plural again — as in vv2-5), suggesting that vv6-19 were indeed the Psalmist\'s own imprecations. <em>Mêʾêt YHWH</em>: from YHWH (the source of the repayment — not human vengeance but divine justice). The Psalmist hands the verdict to God.</p>',
    "21": '<p><strong>וְאַתָּה יְהוִה אֲדֹנָי עֲשֵׂה-אִתִּי לְמַעַן שְׁמֶךָ כִּי-טוֹב חַסְדְּךָ הַצִּילֵנִי</strong> (<em>wĕʾattāh YHWH ʾădōnāy ʿăśêh-ʾittî lĕmaʿan shĕmekā kî-ṭôb ḥasdĕkā haṣṣîlênî</em>, "But you, O Lord GOD, deal with me for the sake of your own name; your steadfast love is good — deliver me!") — the great turn: from imprecation to petition. <em>Wĕʾattāh</em>: "but you" — the pivoting contrast (as in Ps 102:12). The Psalmist does not appeal to his own righteousness (contrast: v20\'s imprecation rests on the enemies\' wickedness) but to the divine character: <em>lĕmaʿan shĕmekā</em> (for the sake of your name — Ps 23:3; 25:11; 31:3; the divine honor at stake in the rescue of the one who bears the divine name). <em>Kî-ṭôb ḥasdĕkā</em>: for your steadfast love is good — the same theology as Ps 107:1.</p>',
    "22": '<p><strong>כִּי-עָנִי וְאֶבְיוֹן אָנֹכִי וְלִבִּי חָלַל בְּקִרְבִּי</strong> (<em>kî-ʿānî wĕʾebyôn ʾānōkhî wĕlibbî ḥālal bĕqirbî</em>, "For I am poor and needy, and my heart is deeply wounded within me!") — <em>ʿānî wĕʾebyôn</em>: poor and needy (the classic pair of the socially vulnerable whom the enemy hounded — v16 — and whom God specifically protects — v31). By describing himself as <em>ʿānî wĕʾebyôn</em>, the Psalmist identifies with the very class the enemy victimized, and claims the divine protection specifically promised to them. <em>Ḥālal bĕqirbî</em>: my heart is pierced/wounded within me (<em>ḥālal</em>: to be pierced, to be slain — the word for the mortally wounded — Isa 53:5: "he was pierced for our transgressions").</p>',
    "23": '<p><strong>כְּצֵל-כִּנְטוֹתוֹ נֶהֱלָכְתִּי נִנְעַרְתִּי כָּאַרְבֶּה</strong> (<em>kĕṣêl-kintōṭô nehĕlākhtî ninʿartî kāʾarbeh</em>, "I am fading like an evening shadow, brushed away like a locust!") — <em>kĕṣêl-kintōṭô</em>: like a shadow at its decline (the long evening shadow that fades rapidly — Ps 102:11; 144:4). <em>Ninʿartî kāʾarbeh</em>: shaken off like a locust (the locust swept away by the wind or brushed off a person — Nah 3:17: "like the locust swarm that settles in the hedges on a cold day" and then vanishes when warmed). Both images convey impermanence and the impossibility of holding on.</p>',
    "24": '<p><strong>בִּרְכַּי כָּשְׁלוּ מִצּוֹם וּבְשָׂרִי כָּחַשׁ מִשָּׁמֶן</strong> (<em>birkay kāshĕlû miṣṣôm ûbĕśārî kāḥash mishshāmen</em>, "My knees buckle from fasting; my body has wasted away, lean and gaunt!") — <em>miṣṣôm</em>: from fasting (the fasting of the Psalmist\'s prayer life — v4: "I am prayer"). The voluntary fast intensifying intercession has physically depleted him. <em>Kāḥash mishshāmen</em>: become lean/wasted without fat (<em>kāḥash</em>: to grow lean, to be gaunt; <em>mishshāmen</em>: from being oily/full — the fat, prosperous body reduced to emaciation). The intercessor\'s physical state mirrors his spiritual condition: depleted but not destroyed.</p>',
    "25": '<p><strong>וַאֲנִי הָיִיתִי חֶרְפָּה לָהֶם יִרְאוּנִי יְנִיעוּן רֹאשָׁם</strong> (<em>waʾănî hāyîtî ḥerpāh lāhem yirʾûnî yĕnîʿûn rōʾshām</em>, "I am the object of their scorn; when they catch sight of me, they shake their heads!") — <em>ḥerpāh</em>: a reproach, the object of public derision (Ps 22:6: "a reproach of men and despised by the people"). <em>Yirʾûnî yĕnîʿûn rōʾshām</em>: "they see me and wag their heads" — the gesture of contemptuous dismissal (2 Kgs 19:21; Lam 2:15: the passers-by hissing and shaking their heads at Jerusalem\'s ruins). Ps 22:7 uses the same phrase for the righteous sufferer, and Matt 27:39 uses it for the mockers at the crucifixion — another thread connecting the Davidic sufferer to the Passion.</p>',
    "26": '<p><strong>עָזְרֵנִי יְהוָה אֱלֹהַי הוֹשִׁיעֵנִי כְחַסְדֶּךָ</strong> (<em>ʿāzĕrênî YHWH ʾĕlōhay hôshîʿênî kĕḥasdekā</em>, "Help me, O LORD my God; save me in keeping with your steadfast love!") — the direct, simple petition after the extended description of suffering (vv22-25). <em>ʿĀzar</em>: to help (the fundamental petition for divine assistance — Ps 121:2: "my help comes from the LORD"). <em>Kĕḥasdekā</em>: according to/in keeping with your steadfast love (the measure of the rescue is the measure of the divine character — not proportional to the Psalmist\'s merit but to the divine <em>ḥesed</em>\'s immensity).</p>',
    "27": '<p><strong>וְיֵדְעוּ כִּי-יָדְךָ זֹּאת אַתָּה יְהוָה עֲשִׂיתָהּ</strong> (<em>wĕyêdĕʿû kî-yādĕkā zōʾt ʾattāh YHWH ʿăśîtāh</em>, "Let them see that your hand is behind this — that you, LORD, are the one who has acted!") — the doxological purpose of the rescue: the witnesses must know (<em>yādaʿ</em>) that this is God\'s hand, not a natural reversal or a human achievement. <em>Yādĕkā zōʾt</em>: this is your hand (the divine fingerprint on the event — Exod 14:31: after the sea crossing, Israel saw the great work that the LORD did and feared him). The rescue serves the universal knowledge of God\'s identity and action.</p>',
    "28": '<p><strong>יְקַלְלוּ-הֵמָּה וְאַתָּה תְבָרֵךְ קָמוּ וַיֵּבֹשׁוּ וְעַבְדְּךָ יִשְׂמָח</strong> (<em>yĕqallĕlû-hêmmāh wĕʾattāh tĕbārêk qāmû wayyêbōshû wĕʿabdĕkā yiśmāḥ</em>, "Let them curse — you will bless. When they rise against me, let them be shamed; but let your servant be glad!") — the great counterpoint: their cursing vs. God\'s blessing. The Psalmist does not ask for the curses to stop but for divine blessing to overwhelm them. <em>Qāmû wayyêbōshû</em>: when they arise, let them be shamed (the reversal of the attackers\' rise). <em>Wĕʿabdĕkā yiśmāḥ</em>: "but your servant will be glad" — the final state: shame for the attackers, joy for the servant. Rom 12:14 echoes the ethic: "bless those who persecute you; bless and do not curse."</p>',
    "29": '<p><strong>יִלְבְּשׁוּ שׂוֹטְנַי כְּלִמָּה וְיַעֲטוּ כַמְעִיל בָּשְׁתָּם</strong> (<em>yilbĕshû śōṭĕnay kĕlimmāh wĕyaʿăṭû khameʿîl bāshtām</em>, "Let my accusers be dressed in disgrace and wrapped in their own shame like a mantle!") — the garment-imagery returns (inverting vv18-19): the enemy wrapped himself in curses as a coat; let the enemies be wrapped in shame as a garment. <em>Kĕlimmāh</em>: disgrace, dishonor (the public humiliation of exposure). <em>Kameʿîl bāshtām</em>: their shame as a robe/mantle (<em>meʿîl</em>: the outer garment — the most visible item of clothing). The image is the exact reversal of the royal robe: where honor should be, shame is draped. The psalm\'s final word on the enemies: clothed in what they deserve.</p>',
    "30": '<p><strong>אוֹדֶה יְהוָה מְאֹד בְּפִי וּבְתוֹךְ רַבִּים אֲהַלְלֶנּוּ</strong> (<em>ʾôdeh YHWH mĕʾōd bĕpî ûbĕtôk rabbîm ʾăhallennû</em>, "With my voice I will give the LORD great thanks; I will praise him among the gathered crowd!") — the psalm moves from petition and imprecation to vow of praise. <em>ʾôdeh YHWH mĕʾōd</em>: I will thank/praise the LORD greatly (<em>mĕʾōd</em>: exceedingly, greatly — the intensity of the thanksgiving matches the intensity of the suffering described). <em>Bĕtôk rabbîm</em>: in the midst of many (the congregation — Ps 22:22,25: "I will tell your name to my brothers; in the midst of the congregation I will praise you"). Public praise as the proper response to personal rescue.</p>',
    "31": '<p><strong>כִּי-יַעֲמֹד לִימִין אֶבְיוֹן לְהוֹשִׁיעַ מִשֹּׁפְטֵי נַפְשׁוֹ</strong> (<em>kî-yaʿămōd lîmîn ʾebyôn lĕhôshîaʿ mishshōpĕṭê napshô</em>, "For he stands at the right hand of the poor person, to rescue him from all who would condemn him!") — the closing verse is the great inversion. V6: the enemy placed an accuser at the Psalmist\'s right hand to condemn him. V31: God stands at the right hand of the <em>ʾebyôn</em> (the poor/needy) to rescue him from those who condemn his soul. The accuser occupies the advocate\'s position (v6); God occupies the advocate\'s position (v31). The one who prosecutes is opposed by the divine defender. This verse became the ground for Christian confidence in Christ as advocate (1 John 2:1: "we have an advocate with the Father, Jesus Christ the righteous") — standing at the right hand where the accuser tried to stand.</p>',
  },
  "110": {
    "2": '<p><strong>מַטֵּה-עֻזְּךָ יִשְׁלַח יְהוָה מִצִּיּוֹן רְדֵה בְּקֶרֶב אֹיְבֶיךָ</strong> (<em>maṭṭêh-ʿuzzĕkā yishlah YHWH miṣṣiyyôn rĕdêh bĕqereb ʾōyĕbêkā</em>, "The LORD extends your powerful scepter from Zion: rule in the midst of your enemies!") — <em>maṭṭêh-ʿuzzĕkā</em>: the rod/scepter of your strength (the symbol of royal authority — Gen 49:10: "the scepter shall not depart from Judah"; Num 24:17: "a scepter shall rise from Israel"). The scepter is sent/stretched out from Zion (the place of the divine throne — Ps 2:6) into the midst of the enemies — not to a safe territory but to the enemy\'s own domain. <em>Rĕdêh bĕqereb ʾōyĕbêkā</em>: "rule in the midst of your enemies!" — the present-tense command to exercise dominion before the enemies are defeated. Sovereignty is exercised in the midst of opposition, not after its resolution (Rom 8:37: "in all these things we are more than conquerors").</p>',
    "3": '<p><strong>עַמְּךָ נְדָבֹת בְּיוֹם חֵילֶךָ בְּהַדְרֵי-קֹדֶשׁ מֵרֶחֶם מִשְׁחָר לְךָ טַל יַלְדֻתֶיךָ</strong> (<em>ʿammĕkā nĕdābōt bĕyôm ḥêlekā bĕhadĕrê-qōdesh mêreḥem mishḥar lĕkā ṭal yaldutêkā</em>, "On the day you march to war, your people are freewill-offerings, in holy splendor; like dew from the womb of the dawn, your young warriors come to you!") — <em>nĕdābōt</em>: freewill-offerings/volunteers (from <em>nādab</em>: to volunteer, to give freely — Judg 5:2: "when the leaders led and the people volunteered, bless the LORD!"; Exod 35:21,29: the free-will giving for the tabernacle). The army is not conscripted but volunteer — those who come because they want to, as freewill offerings. <em>Bĕhadĕrê-qōdesh</em>: in holy splendors (the sacred adornment — Ps 29:2; 96:9; 1 Chr 16:29). <em>Mêreḥem mishḥar lĕkā ṭal yaldutêkā</em>: "from the womb of the dawn, like dew, is your youth/young warriors" — the dawn\'s womb generating dew as rapidly and abundantly as the Messiah\'s army materializes: innumerable, fresh, and forming before anyone expected them (the dew\'s miraculous appearance).</p>',
    "5": '<p><strong>אֲדֹנָי עַל-יְמִינְךָ מָחַץ בְּיוֹם-אַפּוֹ מְלָכִים</strong> (<em>ʾădōnāy ʿal-yĕmînĕkā māḥaṣ bĕyôm-ʾappô mĕlākhîm</em>, "The Lord stands at your right hand; he will crush kings on the day of his wrath!") — a remarkable inversion: in v1, the Messiah sits at YHWH\'s right hand; here, <em>ʾădōnāy</em> (the Lord) is at the Messiah\'s right hand. The two verses together describe a dynamic royal relationship: the Messiah is exalted to YHWH\'s right hand (v1), and YHWH supports the Messiah at his right hand (v5) when he goes into battle. <em>Māḥaṣ bĕyôm-ʾappô mĕlākhîm</em>: he shatters/crushes kings on the day of his wrath (the divine anger making the enthroned Messiah\'s enemies the target — Ps 2:12: "kiss the Son, lest he be angry"). The day of wrath is the day of royal judgment.</p>',
    "6": '<p><strong>יָדִין בַּגּוֹיִם מָלֵא גְוִיּוֹת מָחַץ רֹאשׁ עַל-אֶרֶץ רַבָּה</strong> (<em>yādîn baggôyim māllêʾ gĕwiyyôt māḥaṣ rōʾsh ʿal-ʾereṣ rabbāh</em>, "He will bring judgment on the nations, filling the land with the dead; he will crush the ruler across the wide earth!") — <em>yādîn baggôyim</em>: he executes judgment among the nations (the final worldwide judgment — the scope of the Messiah\'s authority established in Ps 2:8: "I will give you the nations as your inheritance"). <em>Māllêʾ gĕwiyyôt</em>: filling with corpses (<em>gĕwiyyāh</em>: body/corpse — the bodies of the defeated). <em>Māḥaṣ rōʾsh</em>: he shatters the head (the decisive blow to the singular ruler — <em>rōʾsh</em> as the leadership representative — Hab 3:13: "you crushed the head of the house of evil"). The crushing of the head recalls Gen 3:15: "he will crush your head."</p>',
    "7": '<p><strong>מִנַּחַל בַּדֶּרֶךְ יִשְׁתֶּה עַל-כֵּן יָרִים רֹאשׁ</strong> (<em>minnaḥal badderek yishteh ʿal-kên yārîm rōʾsh</em>, "He drinks from the stream along the road, and because of this he will hold his head high!") — the enigmatic final verse of Psalm 110. <em>Minnaḥal badderek yishteh</em>: "from the wadi/stream in the road he drinks" — mid-pursuit, the warrior-king refreshes himself from a stream rather than stopping to make camp. This is the image of relentless pursuit that does not pause for full provision. The parallel is Gideon\'s 300 who lapped water like dogs and kept moving (Judg 7:5-7 — the select few who did not kneel to drink). <em>ʿAl-kên yārîm rōʾsh</em>: "therefore he will lift up his head" (<em>rûm rōʾsh</em>: to raise the head — the gesture of triumph and vindication — Ps 3:3: "you lift up my head"; Gen 40:13,20 — the butler\'s head lifted in restoration). The king who drinks from the stream in the way is refreshed for the final victory.</p>',
  },
}


